/// COMPONENTS ///
import { Container, Row, Col, Form, Button } from 'react-bootstrap';


import { useState } from 'react';
import { Snake } from 'react-snake-lib';

export const Contacts = () => {

    // Contact variables
    const [email, setEmail] = useState('');
    const [message, setMessage] = useState('');

    // Snake minigame variables
    const [gameKey, setGameKey] = useState(0);
    const [score, setScore] = useState(0);
    const [maxScore, setMaxScore] = useState(0);
    const [noWall, setNoWall] = useState(false);

    const onScoreChange = (newScore) => {
        setScore(newScore);
        if (newScore > maxScore) {
            setMaxScore(newScore);
        }
    };

    const onGameOver = () => {
        setGameKey(prevKey => prevKey + 1);
    };

    //on game over reset the score
    const onGameStart = () => {
        setScore(0);
    };


    const boxStyle = {
        position: 'relative',
        margin: 'auto',
        marginTop: '1.5em',
        marginBottom: '1.5em',
        backgroundColor: '#212529',
        color: '#F2F2F2',
        padding: '2em',
        borderRadius: '5px',
        width: '80%',
        opacity: '0.8',
        justifyContent: 'center',
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        console.log('Email:', email);
        console.log('Message:', message);
        // Insert sending mail logic
    };

    return (
        <Container style={boxStyle}>
            <Row >
                <div id='title-presentation'>
                    <h1>contact me</h1>
                </div>
            </Row>
            <Row id='presentation'>
                <Col>
                    <Form onSubmit={handleSubmit}>
                        <Form.Group controlId="formEmail">
                            <Form.Label>Email</Form.Label>
                            <Form.Control
                                type="email"
                                placeholder="insert your email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                            />
                        </Form.Group>
                        <Form.Group controlId="formMessage" className="mt-3">
                            <Form.Label>Message</Form.Label>
                            <Form.Control
                                as="textarea"
                                rows={4}
                                placeholder="insert your max score"
                                value={message}
                                onChange={(e) => setMessage(e.target.value)}
                                required
                            />
                        </Form.Group>
                        <Button variant="primary" type="submit" className="mt-3">Send</Button>
                    </Form>
                </Col>
                <Col id='box-image'>
                    <div style={{ width: '100%' }}>
                        <Row style={{ width: '100%' }}>
                            <Col style={{ textAlign: 'left', fontSize: '20px', fontWeight: 'bold' }}>
                                score: {score}
                            </Col>
                            <Col style={{ textAlign: 'right', fontSize: '20px', fontWeight: 'bold' }}>
                                max: {maxScore}
                            </Col>
                        </Row>
                        <Snake
                            key={gameKey}
                            onScoreChange={onScoreChange}
                            onGameOver={onGameOver}
                            onGameStart={onGameStart}
                            width="90%"
                            bgColor="silver"
                            innerBorderColor="#b1b0b0"
                            snakeSpeed={90}
                            borderColor="black"
                            snakeColor="#3e3e3e"
                            snakeHeadColor="#1a1a1a"
                            appleColor="tomato"
                            borderRadius={5}
                            snakeHeadRadius={1}
                            borderWidth={0}
                            shakeBoard={true}
                            boxShadow="rgba(100, 100, 111, 0.2) 0px 7px 29px 0px"
                            size={16}
                            startGameText="Start Game"
                            startButtonStyle={{
                                color: "white",
                                padding: "6px 20px",
                                backgroundColor: "#1a1a1a",
                                borderRadius: "10px",
                                fontSize: "17px",
                                fontWeight: "600",
                                cursor: "pointer"
                            }}
                            startButtonHoverStyle={{
                                backgroundColor: "#4f4d4d"
                            }}
                            noWall={noWall}
                        />
                        <Col style={{ fontSize: '20px', fontWeight: 'bold', display: 'inline-flex', alignItems: 'center' }}>
                            walls:
                            <Form.Check
                                type="switch"
                                id="noWallSwitch"
                                checked={noWall}
                                onChange={() => setNoWall(prevState => !prevState)}
                                style={{ marginLeft: '10px', marginTop: '10px' }}
                            />
                        </Col>

                    </div>
                </Col>
            </Row >
        </Container >
    );
}